import React, { useState, useEffect, useRef } from 'react';
import { useParams } from 'react-router-dom';

const AiPage = () => {
  const { id } = useParams();
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef(null);
  
  // System prompt based on the current lesson
  const systemPrompts = {
    1: "You are a cybersecurity expert teaching password security best practices...",
    2: "You are a phishing awareness specialist...",
    3: "You are a mobile security consultant...",
    4: "You are a social media privacy expert...",
    5: "You are a web security professional..."
  };

  const systemPrompt = systemPrompts[id] || "You are a helpful cybersecurity assistant.";

  // Initial welcome message
  useEffect(() => {
    const welcomeMessages = {
      1: "Hi! I'm your Password Security Assistant...",
      2: "Hello! I'm your Phishing Detection Helper...",
      3: "Hi there! I'm your Mobile Security Guide...",
      4: "Welcome! I'm your Social Media Privacy Coach...",
      5: "Hey! I'm your Web Safety Advisor..."
    };
    
    setMessages([{ role: 'assistant', content: welcomeMessages[id] || "Hello! How can I help you today?" }]);
  }, [id]);

  // Auto-scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = { role: 'user', content: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await fetch('https://dashscope.aliyuncs.com/compatible-mode/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${process.env.REACT_APP_ALIYUN_KEY}`,
        },
        body: JSON.stringify({
          model: 'qwen-turbo',
          messages: [
            { role: 'system', content: systemPrompt },
            ...messages.slice(-6),
            userMessage
          ]
        })
      });

      if (!response.ok) throw new Error(`HTTP ${response.status}`);

      const data = await response.json();
      const aiResponse = data.choices?.[0]?.message?.content || "I couldn't process that request.";
      
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: aiResponse
      }]);
    } catch (error) {
      console.error('API Error:', error);
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: "Sorry, I'm having trouble connecting to the AI service."
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="content-card">
      {/* ... rest of the component JSX remains the same ... */}
    </div>
  );
};

export default AiPage;
